# Why this push happened. 'cron' = periodic sweep, 'admin' = on-demand UI button, 'register' = subscriber just joined, 'manual' = explicit API call, 'initial' = subscriber boot-time pull.
RuntimeConfigApplyReason = Literal["cron", "admin", "register", "manual", "initial"]

# Payload POSTed by the control plane to each subscriber's /internal/update-runtime-config endpoint.
@dataclass
class RuntimeConfigApplyRequest:
    """Payload POSTed by the control plane to each subscriber's /internal/update-runtime-config endpoint."""
    # Opaque id for tracing (UUIDv4 recommended).
    pushId: str
    reason: 'RuntimeConfigApplyReason'
    snapshot: 'RuntimeConfigSnapshot'

# What a subscriber returns to the control plane after applying (or rejecting) a snapshot.
@dataclass
class RuntimeConfigApplyResponse:
    """What a subscriber returns to the control plane after applying (or rejecting) a snapshot."""
    ok: bool
    # Subscriber-reported service name (matches the subscriber registration).
    service: str
    appliedAt: str
    # Snapshot version the subscriber now holds. May equal previously-held version if no change was needed.
    appliedVersion: int
    # Snapshot version the subscriber held before applying (or 0 on initial apply).
    previousVersion: Optional[int] = None
    # True when the subscriber acknowledged but ignored an older snapshot.
    stale: Optional[bool] = None
    # Older snapshot version ignored when stale=true.
    ignoredVersion: Optional[int] = None
    errors: Optional[List[str]] = field(default_factory=list)

# One config entry. `value` is a free-form JSON value so callers can ship simple strings/numbers or richer JSON objects without rev'ing the schema.
@dataclass
class RuntimeConfigEntry:
    """One config entry. `value` is a free-form JSON value so callers can ship simple strings/numbers or richer JSON objects without rev'ing the schema."""
    env: 'RuntimeConfigEnv'
    # Target service or logical grouping (e.g. 'dd-remote-web-home', 'dd-dev-server', or 'default' for cluster-wide values).
    scope: str
    # Stable per-scope key. Recommend SCREAMING_SNAKE_CASE so it can sit alongside env vars.
    key: str
    # Monotonic per-entry version; the control plane bumps this whenever the value changes.
    version: int
    # ISO-8601 UTC instant at which the control plane wrote this version.
    updatedAt: str
    # Arbitrary JSON value. Producers SHOULD NOT embed secrets here; this payload is logged at every subscriber.
    value: Optional[Any] = None
    # Optional free-form labels (e.g. 'feature-flag', 'rate-limit').
    labels: Optional[List[str]] = field(default_factory=list)
    # Optional metadata: who-changed-it, change-reason, jira ticket, etc.
    meta: Optional[Any] = None

# Top-level namespace for every runtime-config record. Every Redis key, every snapshot, every subscriber registration is scoped to exactly one env. Stage and prod are isolated.
RuntimeConfigEnv = Literal["stage", "prod"]

# Payload sent by a subscriber to POST /subscribers on the control plane.
@dataclass
class RuntimeConfigRegisterRequest:
    """Payload sent by a subscriber to POST /subscribers on the control plane."""
    env: 'RuntimeConfigEnv'
    name: str
    scope: str
    applyUrl: str
    labels: Optional[List[str]] = field(default_factory=list)

# The full set of active entries that apply to a given (env, scope) at a point in time. Subscribers receive this on every push.
@dataclass
class RuntimeConfigSnapshot:
    """The full set of active entries that apply to a given (env, scope) at a point in time. Subscribers receive this on every push."""
    env: 'RuntimeConfigEnv'
    # Subscriber-targeted scope (e.g. 'dd-remote-web-home'). Use '*' for fan-out across all scopes.
    scope: str
    generatedAt: str
    # Monotonic env generation assigned by the control plane. Subscribers MAY ignore an older apply if they already store a greater version.
    snapshotVersion: int
    entries: List['RuntimeConfigEntry']

# One long-running service that wants config pushed to it. Subscribers are env-bound: a single deployment instance can only belong to one env.
@dataclass
class RuntimeConfigSubscriber:
    """One long-running service that wants config pushed to it. Subscribers are env-bound: a single deployment instance can only belong to one env."""
    env: 'RuntimeConfigEnv'
    # Stable unique name; usually the Kubernetes Deployment name (e.g. 'dd-remote-web-home').
    name: str
    # Scope filter applied when building the snapshot for this subscriber.
    scope: str
    # Full URL of the subscriber's apply endpoint (e.g. 'http://dd-remote-web-home.default.svc.cluster.local:8080/internal/update-runtime-config').
    applyUrl: str
    registeredAt: Optional[str] = None
    lastPushAt: Optional[str] = None
    lastPushOk: Optional[bool] = None
    lastPushError: Optional[str] = None
    lastAppliedVersion: Optional[int] = None
    labels: Optional[List[str]] = field(default_factory=list)

# Payload sent by the admin UI (or any operator script) to create or update one entry. The control plane assigns the new version and updatedAt.
@dataclass
class RuntimeConfigUpsertRequest:
    """Payload sent by the admin UI (or any operator script) to create or update one entry. The control plane assigns the new version and updatedAt."""
    env: 'RuntimeConfigEnv'
    scope: str
    key: str
    # Arbitrary JSON value. Producers SHOULD NOT embed secrets here.
    value: Optional[Any] = None
    labels: Optional[List[str]] = field(default_factory=list)
    # Free-form change reason captured in the entry meta (who/why).
    reason: Optional[str] = None
